333					set_signal_status(effect, MAYBE_DIRTY);
334				}
335	
336				if (is_dirty(effect)) {
337					update_effect(effect);
338				}
339	
340				token.ran = false;
341			}
342		});
343	}
344	
345	/**
346	 * @param {() => void | (() => void)} fn
347	 * @returns {Effect}
348	 */
349	export function async_effect(fn) {
350		return create_effect(ASYNC | EFFECT_PRESERVED, fn, true);
351	}
352	
353	/**
354	 * @param {() => void | (() => void)} fn
355	 * @returns {Effect}
356	 */
357	export function render_effect(fn, flags = 0) {
358		return create_effect(RENDER_EFFECT | flags, fn, true);
359	}
360	
361	/**
362	 * @param {(...expressions: any) => void | (() => void)} fn
363	 * @param {Array<() => any>} sync
364	 * @param {Array<() => Promise<any>>} async
365	 */
366	export function template_effect(fn, sync = [], async = []) {
367		flatten(sync, async, (values) => {
368			create_effect(RENDER_EFFECT, () => fn(...values.map(get)), true);
369		});
370	}
371	
372	/**
373	 * @param {(() => void)} fn
374	 * @param {number} flags
375	 */
376	export function block(fn, flags = 0) {
377		var effect = create_effect(BLOCK_EFFECT | flags, fn, true);
378		if (DEV) {
379			effect.dev_stack = dev_stack;
380		}
381		return effect;
382	}
383	
384	/**
385	 * @param {(() => void)} fn
386	 * @param {boolean} [push]
387	 */
388	export function branch(fn, push = true) {
389		return create_effect(BRANCH_EFFECT | EFFECT_PRESERVED, fn, true, push);
390	}
391	
392	/**
393	 * @param {Effect} effect
394	 */
395	export function execute_effect_teardown(effect) {
396		var teardown = effect.teardown;
397		if (teardown !== null) {
398			const previously_destroying_effect = is_destroying_effect;
399			const previous_reaction = active_reaction;
400			set_is_destroying_effect(true);
401			set_active_reaction(null);
402			try {
403				teardown.call(null);
404			} finally {
405				set_is_destroying_effect(previously_destroying_effect);
406				set_active_reaction(previous_reaction);
407			}
408		}
409	}
410	
411	/**
412	 * @param {Effect} signal
413	 * @param {boolean} remove_dom
414	 * @returns {void}
415	 */
416	export function destroy_effect_children(signal, remove_dom = false) {
417		var effect = signal.first;
418		signal.first = signal.last = null;
419	
420		while (effect !== null) {
421			const controller = effect.ac;
422	
423			if (controller !== null) {
424				without_reactive_context(() => {
425					controller.abort(STALE_REACTION);
426				});
427			}
428	
429			var next = effect.next;
430	
431			if ((effect.f & ROOT_EFFECT) !== 0) {
432				// this is now an independent root
433				effect.parent = null;
434			} else {
435				destroy_effect(effect, remove_dom);
436			}
437	
438			effect = next;
439		}
440	}
441	
442	/**
443	 * @param {Effect} signal
444	 * @returns {void}
445	 */
446	export function destroy_block_effect_children(signal) {
447		var effect = signal.first;
448	
449		while (effect !== null) {
450			var next = effect.next;
451			if ((effect.f & BRANCH_EFFECT) === 0) {
452				destroy_effect(effect);
453			}
454			effect = next;
455		}
456	}
457	
458	/**
459	 * @param {Effect} effect
460	 * @param {boolean} [remove_dom]
461	 * @returns {void}
462	 */
463	export function destroy_effect(effect, remove_dom = true) {
464		var removed = false;
465	
466		if (
467			(remove_dom || (effect.f & HEAD_EFFECT) !== 0) &&
468			effect.nodes_start !== null &&
469			effect.nodes_end !== null
470		) {
471			remove_effect_dom(effect.nodes_start, /** @type {TemplateNode} */ (effect.nodes_end));
472			removed = true;
473		}
474	
475		destroy_effect_children(effect, remove_dom && !removed);
476		remove_reactions(effect, 0);
477		set_signal_status(effect, DESTROYED);
478	
479		var transitions = effect.transitions;
480	
481		if (transitions !== null) {
482			for (const transition of transitions) {
483				transition.stop();
484			}
485		}
486	
487		execute_effect_teardown(effect);
488	
489		var parent = effect.parent;
490	
491		// If the parent doesn't have any children, then skip this work altogether
492		if (parent !== null && parent.first !== null) {
493			unlink_effect(effect);
494		}
495	
496		if (DEV) {
497			effect.component_function = null;
498		}
499	
500		// `first` and `child` are nulled out in destroy_effect_children
501		// we don't null out `parent` so that error propagation can work correctly
502		effect.next =
503			effect.prev =
504			effect.teardown =
505			effect.ctx =
506			effect.deps =
507			effect.fn =
508			effect.nodes_start =
509			effect.nodes_end =
510			effect.ac =
511				null;
512	}
513	
514	/**
515	 *
516	 * @param {TemplateNode | null} node
517	 * @param {TemplateNode} end
518	 */
519	export function remove_effect_dom(node, end) {
520		while (node !== null) {
521			/** @type {TemplateNode | null} */
522			var next = node === end ? null : /** @type {TemplateNode} */ (get_next_sibling(node));
523	
524			node.remove();
525			node = next;
526		}
527	}
528	
529	/**
530	 * Detach an effect from the effect tree, freeing up memory and
531	 * reducing the amount of work that happens on subsequent traversals
532	 * @param {Effect} effect
533	 */
534	export function unlink_effect(effect) {
535		var parent = effect.parent;
536		var prev = effect.prev;
537		var next = effect.next;
538	
539		if (prev !== null) prev.next = next;
540		if (next !== null) next.prev = prev;
541	
542		if (parent !== null) {
543			if (parent.first === effect) parent.first = next;
544			if (parent.last === effect) parent.last = prev;
545		}
546	}
547	
548	/**
549	 * When a block effect is removed, we don't immediately destroy it or yank it
550	 * out of the DOM, because it might have transitions. Instead, we 'pause' it.
551	 * It stays around (in memory, and in the DOM) until outro transitions have
552	 * completed, and if the state change is reversed then we _resume_ it.
553	 * A paused effect does not update, and the DOM subtree becomes inert.
554	 * @param {Effect} effect
555	 * @param {() => void} [callback]
556	 */
557	export function pause_effect(effect, callback) {
558		/** @type {TransitionManager[]} */
559		var transitions = [];
560	
561		pause_children(effect, transitions, true);
562	
563		run_out_transitions(transitions, () => {
564			destroy_effect(effect);
565			if (callback) callback();
566		});
567	}
568	
569	/**
570	 * @param {TransitionManager[]} transitions
571	 * @param {() => void} fn
572	 */
573	export function run_out_transitions(transitions, fn) {
574		var remaining = transitions.length;
575		if (remaining > 0) {
576			var check = () => --remaining || fn();
577			for (var transition of transitions) {
578				transition.out(check);
579			}
580		} else {
581			fn();
582		}
583	}
584	
585	/**
586	 * @param {Effect} effect
587	 * @param {TransitionManager[]} transitions
588	 * @param {boolean} local
589	 */
590	export function pause_children(effect, transitions, local) {
591		if ((effect.f & INERT) !== 0) return;
592		effect.f ^= INERT;
593	
594		if (effect.transitions !== null) {
595			for (const transition of effect.transitions) {
596				if (transition.is_global || local) {
597					transitions.push(transition);
598				}
599			}
600		}
601	
602		var child = effect.first;
603	
604		while (child !== null) {
605			var sibling = child.next;
606			var transparent = (child.f & EFFECT_TRANSPARENT) !== 0 || (child.f & BRANCH_EFFECT) !== 0;
607			// TODO we don't need to call pause_children recursively with a linked list in place
608			// it's slightly more involved though as we have to account for `transparent` changing
609			// through the tree.
610			pause_children(child, transitions, transparent ? local : false);
611			child = sibling;
612		}
613	}
614	
615	/**
616	 * The opposite of `pause_effect`. We call this if (for example)
617	 * `x` becomes falsy then truthy: `{#if x}...{/if}`
618	 * @param {Effect} effect
619	 */
620	export function resume_effect(effect) {
621		resume_children(effect, true);
622	}
623	
624	/**
625	 * @param {Effect} effect
626	 * @param {boolean} local
627	 */
628	function resume_children(effect, local) {
629		if ((effect.f & INERT) === 0) return;
630		effect.f ^= INERT;
631	
632		// If a dependency of this effect changed while it was paused,
633		// schedule the effect to update. we don't use `is_dirty`
634		// here because we don't want to eagerly recompute a derived like
635		// `{#if foo}{foo.bar()}{/if}` if `foo` is now `undefined
636		if ((effect.f & CLEAN) === 0) {
637			set_signal_status(effect, DIRTY);
638			schedule_effect(effect);
639		}
640	
641		var child = effect.first;
642	
643		while (child !== null) {
644			var sibling = child.next;
645			var transparent = (child.f & EFFECT_TRANSPARENT) !== 0 || (child.f & BRANCH_EFFECT) !== 0;
646			// TODO we don't need to call resume_children recursively with a linked list in place
647			// it's slightly more involved though as we have to account for `transparent` changing
648			// through the tree.
649			resume_children(child, transparent ? local : false);
650			child = sibling;
651		}
652	
653		if (effect.transitions !== null) {
654			for (const transition of effect.transitions) {
655				if (transition.is_global || local) {
656					transition.in();
657				}
658			}
659		}
660	}
661	
662	export function aborted(effect = /** @type {Effect} */ (active_effect)) {
663		return (effect.f & DESTROYED) !== 0;
664	}
