728	export function untrack(fn) {
729		var previous_untracking = untracking;
730		try {
731			untracking = true;
732			return fn();
733		} finally {
734			untracking = previous_untracking;
735		}
736	}
737	
738	const STATUS_MASK = ~(DIRTY | MAYBE_DIRTY | CLEAN);
739	
740	/**
741	 * @param {Signal} signal
742	 * @param {number} status
743	 * @returns {void}
744	 */
745	export function set_signal_status(signal, status) {
746		signal.f = (signal.f & STATUS_MASK) | status;
747	}
748	
749	/**
750	 * @param {Record<string, unknown>} obj
751	 * @param {string[]} keys
752	 * @returns {Record<string, unknown>}
753	 */
754	export function exclude_from_object(obj, keys) {
755		/** @type {Record<string, unknown>} */
756		var result = {};
757	
758		for (var key in obj) {
759			if (!keys.includes(key)) {
