819			if (
820				proto !== Object.prototype &&
821				proto !== Array.prototype &&
822				proto !== Map.prototype &&
823				proto !== Set.prototype &&
824				proto !== Date.prototype
825			) {
826				const descriptors = get_descriptors(proto);
827				for (let key in descriptors) {
828					const get = descriptors[key].get;
829					if (get) {
830						try {
831							get.call(value);
832						} catch (e) {
833							// continue
834						}
835					}
836				}
837			}
